        if (secondPt.lineValue == 0.0)
        {
            y2 = cy + smufl.tabBendStaffPadding + noteRenderer.getNoteY(note.beat.maxStringNote!!, com.omnifret.gplayer.rendering.NoteYPosition.Center)
        }
        else 
        {
            y2 = cy - smufl.tabBendPerValueHeight * secondPt.lineValue
        }
        this._paintBendLine(
            canvas
            , 
            x1
            , 
            y1
            , 
            x2
            , 
            y2
            , 
            firstPt
            , 
            secondPt
        
        )
        var arrowSize: Double = smufl.glyphWidths.get(com.omnifret.gplayer.model.MusicFontSymbol.ArrowheadBlackDown)!!
        if (firstPt.value != secondPt.value)
        {
            var up: Boolean = secondPt.value > firstPt.value
            this._paintBendLineArrow(
                canvas
                , 
                x2
                , 
                y2
                , 
                y1
                , 
                arrowSize
                , 
                up
            
            )
            this._paintBendLineSlurText(
                canvas
                , 
                x1
                , 
                y1
                , 
                x2
                , 
                y2
                , 
                note
                , 
                res.graceFont
            
            )
            this._paintBendLineValueText(
                canvas
                , 
                y1
                , 
                x2
                , 
                y2 - smufl.tabBendLabelPadding
                , 
                firstPt
                , 
                secondPt
                , 
                res.tablatureFont
            
            )
        }
    }
    
    /**
     */
    private fun _paintBendLineSlurText(canvas: com.omnifret.gplayer.platform.ICanvas, 
    x1: Double, 
    y1: Double, 
    x2: Double, 
    y2: Double, 
    note: com.omnifret.gplayer.model.Note, 
    font: com.omnifret.gplayer.model.Font): Unit{
        if (note.bendStyle == com.omnifret.gplayer.model.BendStyle.Gradual)
        {
            var slurText: String = "grad."
            var size: com.omnifret.gplayer.platform.MeasuredText = canvas.measureText((slurText.toString()))
            canvas.font = font
            var y: Double = 0.0
            var x: Double = 0.0
            if (y1 > y2)
            {
                var h: Double = com.omnifret.gplayer.core.ecmaScript.Math.abs(y1 - y2)
                y = if(h > size.height)  y1 - h / (2.0).toDouble() else y1
                x = (x1 + x2 - size.width) / (2.0).toDouble()
            }
            else 
            {
                y = y1
                x = x2 - size.width
            }
            canvas.fillText((slurText.toString()), x, y)
        }
    }
    
    /**
     */
    private fun _paintBendLineValueText(canvas: com.omnifret.gplayer.platform.ICanvas, 
    y1: Double, 
    x2: Double, 
    y2: Double, 
    firstPt: com.omnifret.gplayer.rendering.glyphs.TabBendRenderPoint, 
    secondPt: com.omnifret.gplayer.rendering.glyphs.TabBendRenderPoint, 
    font: com.omnifret.gplayer.model.Font): Unit{
        if (secondPt.value != 0.0)
        {
            var up: Boolean = secondPt.value > firstPt.value
            var bendValue: Double = secondPt.value
            var bendValueText: String = ""
            if (bendValue == 4.0)
            {
                bendValueText = "full"
                bendValue -= 4.0
            }
            else if (bendValue >= 4 || bendValue <= -4.0)
            {
                var steps: Double = (((bendValue / (4.0).toDouble())).toInt() or 0).toDouble()
                bendValueText += (steps).toInvariantString()
                bendValue -= steps * (4.0).toDouble()
            }
            if (bendValue > 0)
            {
                bendValueText += com.omnifret.gplayer.rendering.glyphs.TabBendGlyph.getFractionSign(bendValue)
            }
            if (bendValueText != "")
            {
                var textY: Double = if(up)  y2 else y1 + (com.omnifret.gplayer.core.ecmaScript.Math.abs(y2 - y1) * (1.0).toDouble()) / (3.0).toDouble()
                canvas.font = font
                var size: com.omnifret.gplayer.platform.MeasuredText = canvas.measureText(bendValueText)
                var textX: Double = x2 - size.width / (2.0).toDouble()
                canvas.fillText(bendValueText, textX, textY)
            }
        }
    }
    
    /**
     */
    private fun _paintBendLineArrow(canvas: com.omnifret.gplayer.platform.ICanvas, 
    x2: Double, 
    y2: Double, 
    y1: Double, 
    arrowSize: Double, 
    up: Boolean): Unit{
        var paramy2 = y2
        if (up)
        {
            if (paramy2 + arrowSize > y1)
            {
                paramy2 = y1 - arrowSize
            }
            canvas.beginPath()
            canvas.moveTo(x2, paramy2)
            canvas.lineTo(x2 - arrowSize * (0.5).toDouble(), paramy2 + arrowSize)
            canvas.lineTo(x2 + arrowSize * (0.5).toDouble(), paramy2 + arrowSize)
            canvas.closePath()
            canvas.fill()
        }
        else 
        {
            if (paramy2 < y1)
            {
                paramy2 = y1 + arrowSize
            }
            canvas.beginPath()
            canvas.moveTo(x2, paramy2)
            canvas.lineTo(x2 - arrowSize * (0.5).toDouble(), paramy2 - arrowSize)
            canvas.lineTo(x2 + arrowSize * (0.5).toDouble(), paramy2 - arrowSize)
            canvas.closePath()
            canvas.fill()
        }
    }
    
    companion object{
        /**
         */
        @kotlin.jvm.JvmStatic
        public fun getFractionSign(steps: Double): String{
            when (steps)
            {
                1.0 -> 
                {
                    return "¼"
                }
                2.0 -> 
                {
                    return "½"
                }
                3.0 -> 
                {
                    return "¾"
                }
                else -> 
                {
                    return """${(steps).toTemplate()}/ 4"""
                }
            }
        }
        
    }
}

